import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../services/api';

const Metrics = () => {
  const { projectId } = useParams();
  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMetrics();
  }, [projectId]);

  const fetchMetrics = async () => {
    try {
      const response = await api.get(`/ai/metrics/${projectId}`);
      setMetrics(response.data.metrics);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching metrics:', error);
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading metrics...</div>;
  }

  if (!metrics) {
    return <div className="alert alert-error">Unable to load metrics</div>;
  }

  return (
    <div className="fade-in">
      <div className="page-header">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '16px' }}>
          <div>
            <h1>Evaluation Metrics</h1>
            <p>Key performance indicators for AI system evaluation</p>
          </div>
          <Link to={`/projects/${projectId}`} className="btn btn-secondary">Back</Link>
        </div>
      </div>

      <div className="grid">
        <div className="card">
          <h3>Sprint Predictability</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#007bff', marginTop: '10px' }}>
            {metrics.sprintPredictability.score}%
          </div>
          <p style={{ marginTop: '10px', color: '#666' }}>{metrics.sprintPredictability.message}</p>
        </div>

        <div className="card">
          <h3>Risk Detection</h3>
          <div style={{ fontSize: '24px', fontWeight: 'bold', marginTop: '10px' }}>
            <span className={`risk-${metrics.riskDetectionTiming?.toLowerCase()}`}>
              {metrics.riskDetectionTiming || 'Low'}
            </span>
          </div>
          <p style={{ marginTop: '10px', color: '#666' }}>Current project risk level</p>
        </div>

        <div className="card">
          <h3>Velocity Stability</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#28a745', marginTop: '10px' }}>
            {metrics.velocityStability.score}%
          </div>
          <p style={{ marginTop: '10px', color: '#666' }}>{metrics.velocityStability.message}</p>
        </div>

        <div className="card">
          <h3>Task Completion Rate</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#17a2b8', marginTop: '10px' }}>
            {metrics.taskCompletionRate.rate}%
          </div>
          <p style={{ marginTop: '10px', color: '#666' }}>{metrics.taskCompletionRate.message}</p>
        </div>
      </div>

      <div className="card" style={{ marginTop: '30px' }}>
        <div className="card-header">Metrics Explanation</div>
        <div style={{ lineHeight: '1.8' }}>
          <h4>Sprint Predictability</h4>
          <p>Measures how accurately planned sprints match actual completion. Higher scores indicate better planning accuracy.</p>

          <h4 style={{ marginTop: '20px' }}>Risk Detection</h4>
          <p>Current risk level of the project based on AI analysis of various factors including missed deadlines, task spillover, and velocity fluctuations.</p>

          <h4 style={{ marginTop: '20px' }}>Velocity Stability</h4>
          <p>Measures consistency of sprint velocity over time. Higher scores indicate more stable and predictable team performance.</p>

          <h4 style={{ marginTop: '20px' }}>Task Completion Rate</h4>
          <p>Percentage of tasks that have been completed across all sprints in the project.</p>
        </div>
      </div>
    </div>
  );
};

export default Metrics;
